/**
 * Content Library Expansion
 * 
 * Generates 500+ lesson templates across 15 industry categories.
 * Each lesson has structured content blocks and quiz questions.
 * 
 * Industries covered:
 * 1. Healthcare & Nursing
 * 2. Retail & Hospitality
 * 3. Manufacturing & Warehousing
 * 4. Construction & Trades
 * 5. Transportation & Logistics
 * 6. Food Service & Restaurant
 * 7. Security & Law Enforcement
 * 8. Cleaning & Facilities
 * 9. Energy & Utilities
 * 10. Agriculture & Farming
 * 11. Education & Childcare
 * 12. IT & Data Centers
 * 13. Mining & Resources
 * 14. Emergency Services
 * 15. General Workplace Skills
 */

import type { LessonContent } from "../drizzle/schema";

export type ExpandedLesson = {
  title: string;
  description: string;
  contentType: "video" | "quiz" | "scenario" | "assessment" | "mixed" | "article";
  durationMinutes: number;
  difficulty: "beginner" | "intermediate" | "advanced";
  category: string;
  industry: string;
  tags: string[];
  language: string;
  content: LessonContent;
};

// ─── Helper Functions ───────────────────────────────────────────────

let blockCounter = 0;
let quizCounter = 0;

function tb(text: string, order: number) {
  blockCounter++;
  return { id: `exp-b${blockCounter}`, type: "text" as const, data: { text }, order };
}

function qq(question: string, options: { text: string; isCorrect: boolean }[], explanation: string) {
  quizCounter++;
  const id = `exp-q${quizCounter}`;
  return {
    id, question, type: "multiple_choice" as const,
    options: options.map((o, i) => ({ id: `${id}-o${i}`, text: o.text, isCorrect: o.isCorrect })),
    explanation, points: 1,
  };
}

function makeLesson(
  title: string,
  description: string,
  category: string,
  industry: string,
  tags: string[],
  difficulty: "beginner" | "intermediate" | "advanced",
  duration: number,
  contentTexts: string[],
  quizzes: Array<{ q: string; opts: { text: string; isCorrect: boolean }[]; exp: string }>,
): ExpandedLesson {
  return {
    title,
    description,
    contentType: quizzes.length > 0 ? "mixed" : "article",
    durationMinutes: duration,
    difficulty,
    category,
    industry,
    tags,
    language: "en",
    content: {
      blocks: contentTexts.map((text, i) => tb(text, i)),
      quizQuestions: quizzes.map(q => qq(q.q, q.opts, q.exp)),
      passingScore: 70,
    },
  };
}

// ─── Content Library ────────────────────────────────────────────────

