  const transportLessons: Array<[string, string, string[], "beginner"|"intermediate"|"advanced", number, string[], Array<{q:string;opts:{text:string;isCorrect:boolean}[];exp:string}>]> = [
    ["Pre-Trip Vehicle Inspection", "Complete a thorough pre-trip inspection to ensure vehicle safety.", ["pre-trip", "inspection", "vehicle"], "beginner", 5,
      ["A proper pre-trip inspection covers:\n\n• Engine compartment: oil, coolant, belts, hoses\n• Cab: mirrors, gauges, controls, seat belt\n• Exterior: tires (tread depth, pressure), lights, reflectors\n• Coupling devices: fifth wheel, kingpin, glad hands\n• Brakes: air pressure, brake adjustment, parking brake\n• Cargo: securement, weight distribution, doors\n\nDocument all findings. Never operate with critical defects."],
      [{q: "What should you check first during a pre-trip inspection?", opts: [{text: "Cargo", isCorrect: false}, {text: "Engine compartment", isCorrect: true}, {text: "Tires only", isCorrect: false}, {text: "Mirrors", isCorrect: false}], exp: "Start with the engine compartment to check fluid levels, belts, and hoses."}]],
    ["Hours of Service (HOS) Regulations", "Understand FMCSA hours of service rules for commercial drivers.", ["HOS", "regulations", "FMCSA", "driving"], "intermediate", 5, ["Key HOS rules for property-carrying drivers:\n\n• 11-Hour Driving Limit: Max 11 hours after 10 consecutive hours off duty\n• 14-Hour Window: Cannot drive after 14 hours on duty\n• 30-Minute Break: Required after 8 cumulative hours of driving\n• 60/70-Hour Limit: Cannot drive after 60/70 hours on duty in 7/8 days\n• Restart: 34 consecutive hours off duty resets the 60/70-hour clock\n\nELD (Electronic Logging Device) is mandatory for recording HOS."], [{q: "How many hours can a property-carrying driver drive after 10 hours off?", opts: [{text: "8 hours", isCorrect: false}, {text: "11 hours", isCorrect: true}, {text: "14 hours", isCorrect: false}, {text: "10 hours", isCorrect: false}], exp: "The 11-Hour Driving Limit allows up to 11 hours of driving after 10 consecutive hours off duty."}]],
    ["Defensive Driving Techniques", "Apply defensive driving strategies to prevent accidents on the road.", ["defensive driving", "safety", "awareness"], "beginner", 4, ["The SMITH System for defensive driving:\n\n1. Aim High in Steering — look 15 seconds ahead\n2. Get the Big Picture — scan the entire scene\n3. Keep Your Eyes Moving — check mirrors every 5-8 seconds\n4. Leave Yourself an Out — maintain space cushion\n5. Make Sure They See You — use signals, lights, horn\n\nThe 4-second following rule: Maintain at least 4 seconds of following distance (increase in bad weather)."], [{q: "What is the recommended following distance in normal conditions?", opts: [{text: "2 seconds", isCorrect: false}, {text: "4 seconds", isCorrect: true}, {text: "6 seconds", isCorrect: false}, {text: "1 second", isCorrect: false}], exp: "Maintain at least 4 seconds of following distance in normal conditions."}]],
    ["Cargo Securement Basics", "Learn proper cargo securement methods to prevent load shifts and spills.", ["cargo", "securement", "load"], "intermediate", 5, ["FMCSA cargo securement rules:\n\n• Cargo must be immobilized or secured\n• Minimum tiedown requirements based on cargo weight\n• Inspect securement within first 50 miles, then every 150 miles or 3 hours\n• Working load limit (WLL) of tiedowns must equal at least 50% of cargo weight\n\nCommon methods: Straps, chains, binders, blocking, bracing, friction mats."], [{q: "When should you first inspect cargo securement after departure?", opts: [{text: "After 100 miles", isCorrect: false}, {text: "Within the first 50 miles", isCorrect: true}, {text: "After 200 miles", isCorrect: false}, {text: "Only at destination", isCorrect: false}], exp: "Inspect cargo securement within the first 50 miles of departure."}]],
    ["Hazmat Transportation Awareness", "Understand hazmat classification, placarding, and emergency procedures.", ["hazmat", "transportation", "placards"], "advanced", 5, ["DOT Hazmat Classes:\n1. Explosives\n2. Gases\n3. Flammable liquids\n4. Flammable solids\n5. Oxidizers\n6. Poisons/Toxic\n7. Radioactive\n8. Corrosives\n9. Miscellaneous\n\nPlacarding required when shipping 1,001+ lbs of a single hazmat class. Shipping papers must be within reach of the driver at all times."], [{q: "When is hazmat placarding required?", opts: [{text: "For any amount", isCorrect: false}, {text: "Over 1,001 lbs of a single class", isCorrect: true}, {text: "Only for Class 1", isCorrect: false}, {text: "Over 5,000 lbs", isCorrect: false}], exp: "Placarding is required when shipping 1,001 pounds or more of a single hazmat class."}]],
  ];

