  const foodServiceLessons: Array<[string, string, string[], "beginner"|"intermediate"|"advanced", number, string[], Array<{q:string;opts:{text:string;isCorrect:boolean}[];exp:string}>]> = [
    ["Food Temperature Danger Zone", "Understand the temperature danger zone and proper food storage temperatures.", ["temperature", "food safety", "danger zone"], "beginner", 4,
      ["The Temperature Danger Zone: 41°F - 135°F (5°C - 57°C)\n\nBacteria multiply rapidly in this range. The 2-Hour Rule: Discard food left in the danger zone for more than 2 hours (1 hour if above 90°F).\n\nSafe temperatures:\n• Cold holding: 41°F (5°C) or below\n• Hot holding: 135°F (57°C) or above\n• Cooking: varies by food (165°F for poultry, 155°F for ground meat, 145°F for fish)\n• Reheating: 165°F (74°C) within 2 hours"],
      [{q: "What is the temperature danger zone?", opts: [{text: "32°F - 100°F", isCorrect: false}, {text: "41°F - 135°F", isCorrect: true}, {text: "50°F - 150°F", isCorrect: false}, {text: "0°F - 200°F", isCorrect: false}], exp: "The danger zone is 41°F to 135°F where bacteria multiply most rapidly."}]],
    ["FIFO: First In, First Out", "Master the FIFO method for proper food rotation and waste reduction.", ["FIFO", "food rotation", "inventory"], "beginner", 3, ["FIFO ensures older products are used first:\n\n1. Date-label all received items\n2. Place new items behind older items\n3. Check dates before using any product\n4. Discard items past their use-by date\n5. Never mix old and new products\n\nBenefits: Reduces waste, prevents serving expired food, maintains quality, saves money."], [{q: "Where should new inventory be placed?", opts: [{text: "In front of older items", isCorrect: false}, {text: "Behind older items", isCorrect: true}, {text: "On a separate shelf", isCorrect: false}, {text: "Wherever there's space", isCorrect: false}], exp: "New items go behind older items so older products are used first."}]],
    ["Knife Safety and Maintenance", "Learn proper knife handling, cutting techniques, and maintenance.", ["knife", "safety", "cutting"], "beginner", 4, ["Knife safety rules:\n\n• A sharp knife is safer than a dull one\n• Cut away from your body\n• Use the right knife for the task\n• Never catch a falling knife — step back\n• Carry knives at your side, point down\n• Never leave knives in soapy water\n• Use a cutting board — never cut in your hand\n\nMaintenance: Hone before each use, sharpen regularly, hand wash and dry immediately."], [{q: "What should you do if a knife is falling?", opts: [{text: "Try to catch it", isCorrect: false}, {text: "Step back and let it fall", isCorrect: true}, {text: "Grab the handle", isCorrect: false}, {text: "Use your foot to stop it", isCorrect: false}], exp: "Never try to catch a falling knife. Step back and let it fall."}]],
    ["ServSafe: Cross-Contamination Prevention", "Prevent cross-contamination through proper food handling and storage.", ["cross-contamination", "food safety", "ServSafe"], "intermediate", 5, ["Cross-contamination occurs when harmful organisms transfer from one surface to another.\n\nPrevention:\n• Separate raw and ready-to-eat foods\n• Store raw meats on bottom shelves (poultry lowest)\n• Use color-coded cutting boards\n• Change gloves between tasks\n• Sanitize surfaces between different food types\n• Never use the same utensils for raw and cooked food\n\nStorage order (top to bottom): Ready-to-eat, seafood, whole cuts of meat, ground meat, poultry"], [{q: "Where should raw poultry be stored in a refrigerator?", opts: [{text: "Top shelf", isCorrect: false}, {text: "Middle shelf", isCorrect: false}, {text: "Bottom shelf", isCorrect: true}, {text: "Anywhere is fine", isCorrect: false}], exp: "Raw poultry should be stored on the bottom shelf to prevent dripping onto other foods."}]],
    ["Proper Handwashing Technique", "Master the FDA-recommended handwashing procedure for food handlers.", ["handwashing", "hygiene", "food safety"], "beginner", 3, ["When to wash hands:\n• Before starting work\n• After using the restroom\n• After touching raw meat/poultry/fish\n• After sneezing, coughing, or touching face\n• After handling garbage\n• After handling money\n• When switching tasks\n\nThe 20-second procedure:\n1. Wet hands with warm water (100°F)\n2. Apply soap\n3. Scrub for 20 seconds (palms, backs, between fingers, under nails)\n4. Rinse thoroughly\n5. Dry with single-use towel\n6. Use towel to turn off faucet"], [{q: "How long should you scrub your hands when washing?", opts: [{text: "5 seconds", isCorrect: false}, {text: "10 seconds", isCorrect: false}, {text: "20 seconds", isCorrect: true}, {text: "60 seconds", isCorrect: false}], exp: "Scrub hands for at least 20 seconds with soap."}]],
  ];

