  const securityLessons: Array<[string, string, string[], "beginner"|"intermediate"|"advanced", number, string[], Array<{q:string;opts:{text:string;isCorrect:boolean}[];exp:string}>]> = [
    ["Situational Awareness for Security", "Develop the observation skills needed for effective security work.", ["awareness", "observation", "security"], "beginner", 4,
      ["Cooper's Color Code of Awareness:\n\n• White — Unaware (dangerous)\n• Yellow — Relaxed alert (baseline for security)\n• Orange — Specific alert (something has caught your attention)\n• Red — High alert (threat confirmed, action required)\n\nSecurity professionals should operate in Yellow at minimum. Scan for: unusual behavior, items out of place, people who don't belong, and environmental changes."],
      [{q: "What is the baseline awareness level for security professionals?", opts: [{text: "White", isCorrect: false}, {text: "Yellow", isCorrect: true}, {text: "Orange", isCorrect: false}, {text: "Red", isCorrect: false}], exp: "Yellow (relaxed alert) is the baseline awareness level for security professionals."}]],
    ["Report Writing for Security", "Write clear, accurate, and legally defensible security reports.", ["report writing", "documentation", "security"], "intermediate", 5, ["Effective security reports follow the 5 W's + H:\n\nWho — All persons involved\nWhat — What happened\nWhen — Date, time, duration\nWhere — Specific location\nWhy — Apparent cause or motive\nHow — How the incident occurred\n\nRules:\n• Write in first person, past tense\n• Be objective — facts only, no opinions\n• Use specific details (not 'a man' but 'a male, approximately 6 feet tall, wearing...')\n• Complete the report before end of shift"], [{q: "What tense should security reports be written in?", opts: [{text: "Present tense", isCorrect: false}, {text: "Past tense", isCorrect: true}, {text: "Future tense", isCorrect: false}, {text: "Any tense", isCorrect: false}], exp: "Security reports should be written in past tense as they document events that have already occurred."}]],
    ["Access Control Procedures", "Manage building access, visitor management, and credential verification.", ["access control", "visitor", "credentials"], "beginner", 4, ["Access control layers:\n\n1. Perimeter — fences, gates, barriers\n2. Building — doors, locks, card readers\n3. Interior — restricted areas, server rooms\n4. Information — passwords, clearances\n\nVisitor management:\n• Verify identity with government-issued ID\n• Log entry time, purpose, and host\n• Issue temporary badge\n• Escort to destination if required\n• Log departure time and collect badge"], [{q: "What should you collect from visitors when they leave?", opts: [{text: "Their car keys", isCorrect: false}, {text: "Their temporary badge", isCorrect: true}, {text: "Their phone number", isCorrect: false}, {text: "Nothing", isCorrect: false}], exp: "Always collect the temporary badge when visitors depart."}]],
    ["De-escalation Techniques", "Learn verbal and non-verbal techniques to de-escalate confrontational situations.", ["de-escalation", "conflict", "communication"], "intermediate", 5, ["The LEAPS model for de-escalation:\n\nL — Listen actively\nE — Empathize with the person\nA — Ask questions to understand\nP — Paraphrase to show understanding\nS — Summarize and offer solutions\n\nBody language:\n• Maintain open posture\n• Keep hands visible\n• Maintain safe distance (arm's length +)\n• Speak slowly and calmly\n• Never point or cross arms"], [{q: "What does the 'E' in LEAPS stand for?", opts: [{text: "Evaluate", isCorrect: false}, {text: "Empathize", isCorrect: true}, {text: "Enforce", isCorrect: false}, {text: "Explain", isCorrect: false}], exp: "E stands for Empathize — showing you understand the person's feelings."}]],
  ];

